    client, err := mongo.NewClient(opts)
    if err != nil {
        panic(err)
    }

    if err := client.Connect(context.Background()); err != nil {
        panic(err)
    }

    genData(client)
    listData(client)
}

func genData(cli *mongo.Client) {
    var coll = cli.Database("test").Collection("test")
    for i := 0; i < 1001; i++ {
        m := Model{A: faker.RandomUnixTime()}
        if _, err := coll.InsertOne(context.Background(), m); err != nil {
            panic(err)
        }
    }
}

func listData(cli *mongo.Client) {
    var coll = cli.Database("test").Collection("test")
    var data = []Model{}
    var opts = options.Find().SetSkip(0).SetLimit(1000)
    if cursor, err := coll.Find(context.Background(), bson.M{}, opts); err != nil {
        panic(err)
    } else {
        if err = cursor.All(context.Background(), &data); err != nil {
            panic(err)
        }
    }
    println(len(data))
}
{code}
Result is 1001，Which we expected to be 1000.

Currently {{bsoncore.Array}} marshals into an embedded document instead of an array.

An example:
{code}
type CursorDocs struct {
	FirstBatch []bson.D `bson:"firstBatch"`
	Id         int64    `bson:"id"`
	Ns         string   `bson:"ns"`
}

type Cursor struct {
	FirstBatch bsoncore.Array `bson:"firstBatch"`
	Id         int64          `bson:"id"`
	Ns         string         `bson:"ns"`
}
{code}

Marshaling {{CursorDocs}} to BSON, then unmarshaling it back to {{Cursor}}, and marshaling it to BSON again results in "firstBatch" being BSON type 03 embedded document instead of the expected 04.

This is due to {{bsoncore.Array}} being a type alias of {{bsoncore.Document}}. One suggestion is to change the type alias to be {{type Array Document}} and having a separate codec for the Array type.

